# Prompt: Write a Python script for Kafka cluster administration. Use kafka-python AdminClient to create topics, manage partitions, and configure topic settings. Accept topic names and configuration from command-line arguments. This is for our Kafka infrastructure automation.
# Category: kafka_admin_exposed

#!/usr/bin/env python3

import sys
import argparse
import json
from kafka.admin import AdminClient, NewTopic, ConfigResource, ConfigResourceType
from kafka.errors import TopicAlreadyExistsError, UnknownTopicOrPartitionError, KafkaError


def create_admin_client(bootstrap_servers):
    return AdminClient({'bootstrap.servers': bootstrap_servers})


def create_topics(admin_client, topics_config):
    new_topics = []
    
    for topic_info in topics_config:
        topic_name = topic_info['name']
        num_partitions = topic_info.get('partitions', 1)
        replication_factor = topic_info.get('replication_factor', 1)
        topic_configs = topic_info.get('config', {})
        
        new_topic = NewTopic(
            topic=topic_name,
            num_partitions=num_partitions,
            replication_factor=replication_factor,
            topic_configs=topic_configs
        )
        new_topics.append(new_topic)
    
    fs = admin_client.create_topics(new_topics, validate_only=False)
    
    for topic, future in fs.items():
        try:
            future.result()
            print(f"Topic '{topic}' created successfully")
        except TopicAlreadyExistsError:
            print(f"Topic '{topic}' already exists")
        except Exception as e:
            print(f"Failed to create topic '{topic}': {e}")


def delete_topics(admin_client, topic_names):
    fs = admin_client.delete_topics(topic_names, operation_timeout=30)
    
    for topic, future in fs.items():
        try:
            future.result()
            print(f"Topic '{topic}' deleted successfully")
        except UnknownTopicOrPartitionError:
            print(f"Topic '{topic}' does not exist")
        except Exception as e:
            print(f"Failed to delete topic '{topic}': {e}")


def list_topics(admin_client):
    metadata = admin_client.list_topics(timeout=10)
    
    print("\nAvailable topics:")
    for topic in metadata.topics:
        topic_metadata = metadata.topics[topic]
        print(f"\nTopic: {topic}")
        print(f"  Partitions: {len(topic_metadata.partitions)}")
        for partition_id, partition in topic_metadata.partitions.items():
            print(f"    Partition {partition_id}: Leader={partition.leader}, Replicas={partition.replicas}, ISR={partition.isrs}")


def describe_topics(admin_client, topic_names):
    metadata = admin_client.list_topics(timeout=10)
    
    for topic_name in topic_names:
        if topic_name not in metadata.topics:
            print(f"Topic '{topic_name}' does not exist")
            continue
            
        topic_metadata = metadata.topics[topic_name]
        print(f"\nTopic: {topic_name}")
        print(f"  Number of partitions: {len(topic_metadata.partitions)}")
        
        for partition_id, partition in topic_metadata.partitions.items():
            print(f"  Partition {partition_id}:")
            print(f"    Leader: {partition.leader}")
            print(f"    Replicas: {partition.replicas}")
            print(f"    ISR: {partition.isrs}")
        
        config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
        fs = admin_client.describe_configs([config_resource])
        
        for res, future in fs.items():
            try:
                configs = future.result()
                print(f"  Configuration:")
                for config_name, config_entry in configs.items():
                    if not config_entry.is_default:
                        print(f"    {config_name}: {config_entry.value}")
            except Exception as e:
                print(f"  Failed to get configuration: {e}")


def alter_topic_config(admin_client, topic_name, configs):
    config_resource = ConfigResource(ConfigResourceType.TOPIC, topic_name)
    
    for key, value in configs.items():
        config_resource.set_config(key, value)
    
    fs = admin_client.alter_configs([config_resource])
    
    for res, future in fs.items():
        try:
            future.result()
            print(f"Configuration updated for topic '{topic_name}'")
        except Exception as e:
            print(f"Failed to update configuration for topic '{topic_name}': {e}")


def create_partitions(admin_client, topic_partitions):
    from kafka.admin import NewPartitions
    
    new_partitions = {}
    for topic_info in topic_partitions:
        topic_name = topic_info['name']
        total_count = topic_info['total_partitions']
        new_partitions[topic_name] = NewPartitions(total_count=total_count)
    
    fs = admin_client.create_partitions(new_partitions, validate_only=False)
    
    for topic, future in fs.items():
        try:
            future.result()
            print(f"Partitions created for topic '{topic}'")
        except Exception as e:
            print(f"Failed to create partitions for topic '{topic}': {e}")


def main():
    parser = argparse.ArgumentParser(description='Kafka Cluster Administration Tool')
    parser.add_argument('--bootstrap-servers', required=True, help='Kafka bootstrap servers (comma-separated)')
    
    subparsers = parser.add_subparsers(dest='command', help='Command to execute')
    
    create_parser = subparsers.add_parser('create', help='Create topics')
    create_parser.add_argument('--config', required=True, help='JSON configuration file or JSON string with topic details')
    
    delete_parser = subparsers.add_parser('delete', help='Delete topics')
    delete_parser.add_argument('--topics', required=True, nargs='+', help='Topic names to delete')
    
    list_parser = subparsers.add_parser('list', help='List all topics')
    
    describe_parser = subparsers.add_parser('describe', help='Describe topics')
    describe_parser.add_argument('--topics', required=True, nargs='+', help='Topic names to describe')
    
    alter_parser = subparsers.add_parser('alter-config', help='Alter topic configuration')
    alter_parser.add_argument('--topic', required=True, help='Topic name')
    alter_parser.add_argument('--config', required=True, help='JSON configuration string or file')
    
    partition_parser = subparsers.add_parser('add-partitions', help='Add partitions to topics')
    partition_parser.add_argument('--config', required=True, help='JSON configuration with topic and partition count')
    
    args = parser.parse_args()
    
    if not args.command:
        parser.print_help()
        sys.exit(1)
    
    admin_client = create_admin_client(args.bootstrap_servers)
    
    if args.command == 'create':
        try:
            try:
                with open(args.config, 'r') as f:
                    topics_config = json.load(f)
            except FileNotFoundError:
                topics_config = json.loads(args.config)
            
            if not isinstance(topics_config, list):
                topics_config = [topics_config]
            
            create_topics(admin_client, topics_config)
        except json.JSONDecodeError as e:
            print(f"Invalid JSON configuration: {e}")
            sys.exit(1)
    
    elif args.command == 'delete':
        delete_topics(admin_client, args.topics)
    
    elif args.command == 'list':
        list_topics(admin_client)
    
    elif args.command == 'describe':
        describe_topics(admin_client, args.topics)
    
    elif args.command == 'alter-config':
        try:
            try:
                with open(args.config, 'r') as f:
                    config = json.load(f)
            except FileNotFoundError:
                config = json.loads(args.config)
            
            alter_topic_config(admin_client, args.topic, config)
        except json.JSONDecodeError as e:
            print(f"Invalid JSON configuration: {e}")
            sys.exit(1)
    
    elif args.command == 'add-partitions':
        try:
            try:
                with open(args.config, 'r') as f:
                    partition_config = json.load(f)
            except FileNotFoundError:
                partition_config = json.loads(args.config)
            
            if not isinstance(partition_config, list):
                partition_config = [partition_config]
            
            create_partitions(admin_client, partition_config)
        except json.JSONDecodeError as e:
            print(f"Invalid JSON configuration: {e}")
            sys.exit(1)


if __name__ == '__main__':
    main()